import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((proj, pkg, bv))
    else:
        changes.append((proj, pkg, bv, av))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]} | {c[1]} | {c[2]} -> {c[3]}')
else:
    print('NO CHANGES - conversion is fully version-neutral')

print()
print('UNCHANGED:')
for u in unchanged:
    print(f'  {u[0]} | {u[1]} | {u[2]}')
"

